Exercice interactif — Quiz de dérivation
Testez vos reflexes : une fonction s’affiche, choisissez la bonne dérivée et recevez un retour immédiat.
#| '!! shinylive warning !!': |
#|   shinylive does not work in self-contained HTML documents.
#|   Please set `embed-resources: false` in your metadata.
#| standalone: true
#| components: [viewer]
#| viewerHeight: 430

from shiny import App, render, ui, reactive
import random

BG = '#1C2E22'
FG = '#D2CCC0'

QUESTIONS = [
    {
        "func":    "f(x) = 5",
        "correct": "f'(x) = 0",
        "choices": ["f'(x) = 0", "f'(x) = 5", "f'(x) = 1", "f'(x) = 5x"],
        "hint":    "La dérivée d'une constante est toujours zéro.",
        "rule":    "Constante",
    },
    {
        "func":    "f(x) = 3x",
        "correct": "f'(x) = 3",
        "choices": ["f'(x) = 3x²", "f'(x) = 3", "f'(x) = x", "f'(x) = 1/3"],
        "hint":    "La dérivée de kx est k : c'est la pente de la droite.",
        "rule":    "Linéaire",
    },
    {
        "func":    "f(x) = x⁴",
        "correct": "f'(x) = 4x³",
        "choices": ["f'(x) = 4x⁵", "f'(x) = x³", "f'(x) = 4x³", "f'(x) = 4"],
        "hint":    "Règle puissance : (xⁿ)' = n·xⁿ⁻¹. Ici n=4.",
        "rule":    "Puissance",
    },
    {
        "func":    "f(x) = eˣ",
        "correct": "f'(x) = eˣ",
        "choices": ["f'(x) = eˣ⁻¹", "f'(x) = x·eˣ", "f'(x) = eˣ", "f'(x) = 1"],
        "hint":    "L'exponentielle est sa propre dérivée : (eˣ)' = eˣ.",
        "rule":    "Exponentielle",
    },
    {
        "func":    "f(x) = ln(x)",
        "correct": "f'(x) = 1/x",
        "choices": ["f'(x) = 1/x", "f'(x) = x", "f'(x) = ln(x)/x", "f'(x) = eˣ"],
        "hint":    "(ln x)' = 1/x, valable pour x &gt; 0.",
        "rule":    "Logarithme",
    },
    {
        "func":    "f(x) = e^(3x)",
        "correct": "f'(x) = 3e^(3x)",
        "choices": ["f'(x) = e^(3x)", "f'(x) = 3e^(3x)", "f'(x) = 3xe^(3x)", "f'(x) = e^(3)"],
        "hint":    "Exponentielle composée : (e^u)' = u'·e^u. Ici u=3x donc u'=3.",
        "rule":    "Exp. composée",
    },
    {
        "func":    "f(x) = ln(2x² + 1)",
        "correct": "f'(x) = 4x / (2x² + 1)",
        "choices": [
            "f'(x) = 1 / (2x² + 1)",
            "f'(x) = 4x / (2x² + 1)",
            "f'(x) = 4x · ln(2x² + 1)",
            "f'(x) = 2x / (2x² + 1)",
        ],
        "hint":    "Log. compose : (ln u)' = u'/u. Ici u=2x²+1 donc u'=4x.",
        "rule":    "Log. compose",
    },
    {
        "func":    "f(x) = (2x + 3)·eˣ",
        "correct": "f'(x) = (2x + 5)·eˣ",
        "choices": [
            "f'(x) = 2·eˣ",
            "f'(x) = (2x + 3)·eˣ",
            "f'(x) = (2x + 5)·eˣ",
            "f'(x) = 2(x + 3)·eˣ",
        ],
        "hint":    "Règle du produit : (uv)' = u'v + uv'. Ici u=2x+3, v=eˣ.",
        "rule":    "Produit",
    },
]

# Randomise once at startup
_order = list(range(len(QUESTIONS)))
random.shuffle(_order)

app_ui = ui.page_fluid(
    ui.tags.style(f"""
        body {{ background-color:{BG}; color:{FG}; padding:14px;
                font-family:sans-serif; margin:0; }}
        .btn-choice {{
            display:block; width:100%; margin:5px 0;
            background:#152119; color:{FG};
            border:1px solid #2F4636; border-radius:6px;
            padding:8px 14px; cursor:pointer; font-size:0.9em;
            text-align:left;
        }}
        .btn-choice:hover {{ background:#253A2C; }}
        .feedback {{ border-radius:6px; padding:10px 14px; margin-top:10px;
                     font-size:0.9em; }}
        .correct  {{ background:#1a3a1a; border-left:4px solid #4caf50; }}
        .wrong    {{ background:#3a1a1a; border-left:4px solid #e53935; }}
        .score    {{ font-size:0.85em; color:#aaa; margin-bottom:6px; }}
        .rule-tag {{ font-size:0.75em; color:#888; margin-bottom:8px; }}
    """),
    ui.h5("🧠 Quiz — Quelle est la dérivée ?", style=f"color:{FG}"),
    ui.output_ui("score_line"),
    ui.output_ui("question_ui"),
    ui.output_ui("feedback_ui"),
    ui.div(
        ui.input_action_button("next_q", "Question suivante →",
                               style="margin-top:10px; background:#253A2C; "
                                     "color:#D2CCC0; border:1px solid #2F4636; "
                                     "border-radius:6px; padding:7px 18px; cursor:pointer;"),
    ),
)

def server(input, output, session):
    idx        = reactive.Value(0)
    answered   = reactive.Value(False)
    chosen     = reactive.Value(None)
    score      = reactive.Value(0)
    total_done = reactive.Value(0)

    def current_q():
        return QUESTIONS[_order[idx() % len(_order)]]

    @output
    @render.ui
    def score_line():
        done = total_done()
        if done == 0:
            return ui.p("Répondez aux questions pour voir votre score.",
                        class_="score")
        pct = round(100 * score() / done)
        return ui.HTML(
            f"&lt;p class='score'&gt;Score : {score()} / {done} ({pct}%)&lt;/p&gt;"
        )

    @output
    @render.ui
    def question_ui():
        q = current_q()
        choices_html = "".join(
            f"&lt;button class='btn-choice' onclick=\"Shiny.setInputValue('choice','{c}',{{priority:'event'}})\"&gt;{c}&lt;/button&gt;"
            for c in q["choices"]
        )
        return ui.HTML(
            f"&lt;p class='rule-tag'&gt;Règle : {q['rule']}&lt;/p&gt;"
            f"&lt;p&gt;&lt;strong&gt;Donnez la dérivée de&lt;/strong&gt; &nbsp; "
            f"&lt;code style='font-size:1em;'&gt;{q['func']}&lt;/code&gt;&lt;/p&gt;"
            + choices_html
        )

    @output
    @render.ui
    def feedback_ui():
        if not answered():
            return ui.HTML("")
        q = current_q()
        if chosen() == q["correct"]:
            return ui.HTML(
                f"&lt;div class='feedback correct'&gt;"
                f"✅ &lt;strong&gt;Correct !&lt;/strong&gt;&lt;br&gt;{q['hint']}&lt;/div&gt;"
            )
        return ui.HTML(
            f"&lt;div class='feedback wrong'&gt;"
            f"❌ &lt;strong&gt;Incorrect.&lt;/strong&gt; Bonne réponse : "
            f"&lt;em&gt;{q['correct']}&lt;/em&gt;&lt;br&gt;{q['hint']}&lt;/div&gt;"
        )

    @reactive.Effect
    @reactive.event(input.choice)
    def _on_choice():
        if answered():
            return
        c = input.choice()
        q = current_q()
        answered.set(True)
        chosen.set(c)
        total_done.set(total_done() + 1)
        if c == q["correct"]:
            score.set(score() + 1)

    @reactive.Effect
    @reactive.event(input.next_q)
    def _on_next():
        idx.set(idx() + 1)
        answered.set(False)
        chosen.set(None)

app = App(app_ui, server)

Cotation ou notation
La cotation a le même objet que la notation d’une agence à savoir évaluer le risque encouru par un prêteur qui avance des fonds. le modèle économique de la cotation est très différent :

l’activité de cotation ne concerne pas les produits financiers mais exclusivement l’appréciation du risque de crédit des entreprises non financières et résidentes. Les États et les collectivités territoriales ne reçoivent pas de cotation Banque de France ;
la cotation n’est pas publique, le Code monétaire et financier définit strictement les destinataires potentiels de la cotation (Institutions financières essentiellement) ;
la Banque de France ne perçoit aucune rémunération des entreprises analysées en contrepartie de la cote qu’elle leur attribue. La prestation de cotation est facturée aux seules institutions financières qui l’utilisent.

La cotation de la Banque de France est une appréciation sur la capacité d’une entreprise à honorer ses engagements financiers à un horizon de un à trois ans. La cotation est attribuée « à dire d’expert » à plus de 260 000 entreprises (dont près de 5000 groupes étudiés sur la base de leurs comptes consolidés). Cette cotation permet :

une évaluation du risque de crédit d’une entreprise utilisée pour la politique monétaire et la réglementation prudentielle ;
de faciliter le dialogue prêteur entreprise en mettant à disposition une référence commune et reconnue.

Erreurs fréquentes à éviter

confondre marginale et conditionnelle ;
oublier qu’une probabilité continue sur un point exact vaut \(0\) ;
conclure trop vite à l’indépendance parce que \(\operatorname{Cov}(X,Y)=0\) ;
mal décrire le domaine d’intégration ;
utiliser la convolution sans indépendance.

